// worker-public.js
export default {
  async fetch(request, env, ctx) {
    const url = new URL(request.url);
    const path = url.pathname;

    try {
      if (path.startsWith('/api/users')) {
        const userServiceResponse = await env.USER_SERVICE.fetch(request.clone());
        return userServiceResponse;
      } else if (path.startsWith('/api/products')) {
        const productServiceResponse = await env.PRODUCT_SERVICE.fetch(request.clone());
        return productServiceResponse;
      } else if (path.startsWith('/api/orders')) {
        const orderServiceResponse = await env.ORDER_SERVICE.fetch(request.clone());
        return orderServiceResponse;
      } else if (path.startsWith('/api/analytics')) {
        const analyticsServiceResponse = await env.ANALYTICS_SERVICE.fetch(request.clone());
        return analyticsServiceResponse;
      } else if (path === '/health') {
        const healthChecks = await Promise.all([
          env.USER_SERVICE.fetch(new Request('http://internal/health')),
          env.PRODUCT_SERVICE.fetch(new Request('http://internal/health')),
          env.ORDER_SERVICE.fetch(new Request('http://internal/health')),
          env.ANALYTICS_SERVICE.fetch(new Request('http://internal/health'))
        ]);

        const allHealthy = healthChecks.every(response => response.ok);
        
        return new Response(JSON.stringify({
          status: allHealthy ? 'healthy' : 'degraded',
          services: {
            user: healthChecks[0].ok,
            product: healthChecks[1].ok,
            order: healthChecks[2].ok,
            analytics: healthChecks[3].ok
          },
          timestamp: new Date().toISOString()
        }), {
          status: allHealthy ? 200 : 503,
          headers: { 'Content-Type': 'application/json' }
        });
      } else {
        return new Response(JSON.stringify({
          error: 'Not Found',
          message: 'The requested endpoint does not exist'
        }), {
          status: 404,
          headers: { 'Content-Type': 'application/json' }
        });
      }
    } catch (error) {
      return new Response(JSON.stringify({
        error: 'Internal Server Error',
        message: error.message
      }), {
        status: 500,
        headers: { 'Content-Type': 'application/json' }
      });
    }
  }
};

// worker-user-service.js
export default {
  async fetch(request, env, ctx) {
    const url = new URL(request.url);
    const path = url.pathname;

    if (path === '/health') {
      return new Response(JSON.stringify({ status: 'ok', service: 'user' }), {
        status: 200,
        headers: { 'Content-Type': 'application/json' }
      });
    }

    if (path === '/api/users' && request.method === 'GET') {
      const users = await env.USER_KV.get('users', { type: 'json' }) || [];
      return new Response(JSON.stringify(users), {
        headers: { 'Content-Type': 'application/json' }
      });
    }

    if (path === '/api/users' && request.method === 'POST') {
      const userData = await request.json();
      const userId = crypto.randomUUID();
      const newUser = {
        id: userId,
        ...userData,
        createdAt: new Date().toISOString()
      };

      const users = await env.USER_KV.get('users', { type: 'json' }) || [];
      users.push(newUser);
      await env.USER_KV.put('users', JSON.stringify(users));

      ctx.waitUntil(
        env.ANALYTICS_SERVICE.fetch(new Request('http://internal/api/analytics/event', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            event: 'user_created',
            userId: userId,
            timestamp: new Date().toISOString()
          })
        }))
      );

      return new Response(JSON.stringify(newUser), {
        status: 201,
        headers: { 'Content-Type': 'application/json' }
      });
    }

    if (path.match(/^\/api\/users\/[^/]+$/) && request.method === 'GET') {
      const userId = path.split('/').pop();
      const users = await env.USER_KV.get('users', { type: 'json' }) || [];
      const user = users.find(u => u.id === userId);

      if (!user) {
        return new Response(JSON.stringify({ error: 'User not found' }), {
          status: 404,
          headers: { 'Content-Type': 'application/json' }
        });
      }

      return new Response(JSON.stringify(user), {
        headers: { 'Content-Type': 'application/json' }
      });
    }

    return new Response(JSON.stringify({ error: 'Not Found' }), {
      status: 404,
      headers: { 'Content-Type': 'application/json' }
    });
  }
};

